mapper.select:
SELECT 전담자번호 memberNo, 지점 branch, 이름 memberName, 아이디 userId, 권한 role, 관리자권한 isAdmin, 등록일 regDate, 이메일 email, 전화번호 phoneNumber, 아이디사용여부 useStatus, 입사일 hireDate, 최종발령일 lastAssignDate, 근속기간구분 continuousPeriod, 조회순서 viewOrder, 실적작성여부 performanceWrite, 일일업무일지발급여부 dailyReportIssue, 배정가중치 assignWeight FROM J_참여자관리_로그인정보 WHERE 1=1
AND 지점 = #{searchBranch}
AND 이름 LIKE '%' + #{searchName} + '%'
AND 아이디 LIKE '%' + #{searchUserId} + '%'
AND 권한 = #{searchRole}
ORDER BY 조회순서 ASC, 전담자번호 ASC

mapper.insert:
INSERT INTO J_참여자관리_로그인정보 (
    전담자번호, 지점, 이름, 아이디, 비밀번호, 권한, 관리자권한,
    이메일, 전화번호, 아이디사용여부, 입사일, 최종발령일,
    조회순서, 실적작성여부, 일일업무일지발급여부, 배정가중치
) VALUES (
    #{memberNo}, #{branch}, #{memberName}, #{userId}, #{password}, #{role}, #{isAdmin},
    #{email}, #{phoneNumber}, #{useStatus}, #{hireDate}, #{lastAssignDate},
    #{viewOrder}, #{performanceWrite}, #{dailyReportIssue}, #{assignWeight}
)

mapper.update:
UPDATE J_참여자관리_로그인정보
SET 비밀번호 = #{password}
WHERE 전담자번호 = #{memberNo}

mapper.select:
SELECT A.구직번호 jobNo, A.참여자 participantName, A.생년월일 birthDate, A.성별 gender, A.지점 branch, A.전담자_계정 counselorAccount, A.진행단계 progressStage, CONVERT(varchar, A.등록일, 23) participantRegDate, A.마감 closed FROM J_참여자관리 A WHERE 1=1
AND CAST(A.구직번호 AS NVARCHAR) LIKE #{searchJobNo} + '%'
AND A.참여자 LIKE '%' + #{searchName} + '%'
AND A.지점 = #{searchBranch}
AND A.진행단계 = #{searchStatus}
AND A.등록일 >= #{searchStartDate}
AND A.등록일 <= #{searchEndDate}
AND A.마감 = #{searchClosed}
ORDER BY A.구직번호 DESC

SELECT PK pk, 지점 reportBranch, 아이디 reportUserId, 유형1 type1, 유형2 type2, 금일일반취업 dailyGeneralEmp, 금일알선취업 dailyPlacementEmp, 금주일반취업 weekGeneralEmp, 금주알선취업 weekPlacementEmp, 금월일반취업 monthGeneralEmp, 금월알선취업 monthPlacementEmp, 금년일반취업 yearGeneralEmp, 금년알선취업 yearPlacementEmp, CONVERT(varchar, 업무보고일, 23) reportDate, CONVERT(varchar, 실적등록일, 120) reportRegDate FROM J_참여자관리_일일업무보고 WHERE 1=1
AND 지점 = #{searchBranch}
AND 아이디 LIKE '%' + #{searchUserId} + '%'
AND 업무보고일 = #{reportDate}
ORDER BY PK DESC

mapper.insert:
INSERT INTO J_참여자관리_기준금액 (PK, 구분, 년도, 임금_최소, 임금_최대, 성공금)
VALUES (
    (SELECT ISNULL(MAX(PK), 0) + 1 FROM J_참여자관리_기준금액),
    #{division}, #{year}, #{minWage}, #{maxWage}, #{successFee}
)

INSERT INTO J_참여자관리_나은기준임금 (PK, 년도, 등록일, 년도DATE, 나은임금)
VALUES (
    (SELECT ISNULL(MAX(PK), 0) + 1 FROM J_참여자관리_나은기준임금),
    #{betterYear}, GETDATE(), #{betterYearDate}, #{betterWage}
)

mapper.update:
UPDATE J_참여자관리_나은기준임금
SET
    년도 = #{betterYear},
    년도DATE = #{betterYearDate},
    나은임금 = #{betterWage}
WHERE PK = #{pk}

mapper.insert:
INSERT INTO J_참여자관리_알선상세정보 (
    등록번호, 구직번호, 상세정보, 추천사, 등록일, 수정일
) VALUES (
    (SELECT ISNULL(MAX(등록번호), 0) + 1 FROM J_참여자관리_알선상세정보),
    #{placementJobNo}, #{detailInfo}, #{recommendation}, GETDATE(), GETDATE()
)

INSERT INTO J_참여자관리_자격증 (
    자격증번호, 구직번호, 자격증
) VALUES (
    (SELECT ISNULL(MAX(자격증번호), 0) + 1 FROM J_참여자관리_자격증),
    #{certJobNo}, #{certificateName}
)

mapper.update:
UPDATE J_참여자관리_자격증
SET 자격증 = #{certificateName}
WHERE 자격증번호 = #{certificateNo}

mapper.insert:
INSERT INTO J_참여자관리_직업훈련 (
    직업훈련번호, 구직번호, 직업훈련
) VALUES (
    (SELECT ISNULL(MAX(직업훈련번호), 0) + 1 FROM J_참여자관리_직업훈련),
    #{trainJobNo}, #{trainingName}
)

mapper.update:
UPDATE J_참여자관리_직업훈련
SET 직업훈련 = #{trainingName}
WHERE 직업훈련번호 = #{trainingNo}
